/** @jest-environment jsdom */

import { openCotizacionesListPdf } from "../pdf";

const records = [
  {
    id: "cot-1",
    codigo: "COT-123456",
    clientId: 1,
    projectId: 1,
    clienteNombre: "Roberto Fuentes",
    clienteTelefono: "+56 9 8234 5678",
    obra: "Casa Coquimbo",
    direccion: "Los Pescadores 221",
    validez: "15 dias",
    descuentoPct: 0,
    observaciones: "",
    estado: "creada" as const,
    createdAt: "2026-03-14T10:00:00.000Z",
    updatedAt: "2026-03-14T10:00:00.000Z",
    items: [],
    subtotal: 100000,
    descuentoValor: 0,
    neto: 100000,
    iva: 19000,
    flete: 0,
    total: 119000,
  },
];

describe("pdf utils", () => {
  afterEach(() => {
    jest.restoreAllMocks();
  });

  it("debe abrir una ventana imprimible con el listado de cotizaciones", () => {
    const write = jest.fn();
    const close = jest.fn();
    const openSpy = jest.spyOn(window, "open").mockReturnValue({
      document: {
        write,
        close,
      },
    } as unknown as Window);

    openCotizacionesListPdf(records, "Exportacion");

    expect(openSpy).toHaveBeenCalled();
    expect(write).toHaveBeenCalledWith(expect.stringContaining("COT-123456"));
    expect(write).toHaveBeenCalledWith(expect.stringContaining("Roberto Fuentes"));
    expect(close).toHaveBeenCalled();
  });

  it("debe fallar si el navegador bloquea la ventana de impresion", () => {
    jest.spyOn(window, "open").mockReturnValue(null);

    expect(() => openCotizacionesListPdf(records)).toThrow(
      "No se pudo abrir la ventana de impresion"
    );
  });
});
